import 'dart:async';
import 'dart:developer';

import 'package:flutter/material.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

import '../debug_page_state.dart';

final debugPageStateProvider =
    StateNotifierProvider.autoDispose<DebugPageStateNotifier, DebugPageState>(
        (ref) => DebugPageStateNotifier());

class DebugPageStateNotifier extends StateNotifier<DebugPageState> {
  DebugPageStateNotifier() : super(const DebugPageState());
  Timer? timer;

  startTimer() {

    // update state every 1 sec.
    timer ??= Timer.periodic(const Duration(seconds: 1), (timer) {
      state = state.copyWith(count: timer.tick);
    });
  }
}

class DebugPage extends HookConsumerWidget {
  const DebugPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final notifier = ref.watch(debugPageStateProvider.notifier);
    final state = ref.watch(debugPageStateProvider);

    notifier.startTimer();

    return Column(
      children: [
        Text(state.count.toString()),
        SelectableText('selectable text',
            contextMenuBuilder: (context, editableTextState) {
          log('contextMenuBuilder is called');
          return AdaptiveTextSelectionToolbar.buttonItems(
            buttonItems: [
              ContextMenuButtonItem(onPressed: () {}, label: 'menu'),
              ...editableTextState.contextMenuButtonItems,
            ],
            anchors: editableTextState.contextMenuAnchors,
          );
        }),
      ],
    );
  }
}

