@hayashikun You are seeing the same problem, but in a different form. Since the stateless widget rebuilds, the context menu also has to. For this case, you can pass the context menu builder down to the stateless widget.

<details>

<summary>Updated Stateless Widget sample</summary>

```dart
import 'dart:async';

import 'package:flutter/material.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        useMaterial3: true,
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});

  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  int _counter = 0;
  Timer? timer;

  @override
  void initState() {
    super.initState();
    // update state every 1 sec.
    timer ??= Timer.periodic(const Duration(seconds: 1), (timer) {
      if (!mounted) {
        return;
      }

      setState(() {
        _counter = timer.tick;
      });
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text(widget.title)),
      body: Texts(
        counter: _counter,
        contextMenuBuilder: _contextMenuBuilder,
      ),
    );
  }

  Widget _contextMenuBuilder(
    BuildContext context,
    EditableTextState editableTextState,
  ) {
    print('contextMenuBuilder 2 is called');
    return AdaptiveTextSelectionToolbar.buttonItems(
      buttonItems: [
        ContextMenuButtonItem(onPressed: () {}, label: 'menu'),
        ...editableTextState.contextMenuButtonItems,
      ],
      anchors: editableTextState.contextMenuAnchors,
    );
  }

  @override
  void dispose() {
    timer?.cancel();
    timer = null;
    super.dispose();
  }
}

class Texts extends StatelessWidget {
  final int counter;

  final Widget Function(BuildContext, EditableTextState) contextMenuBuilder;

  const Texts({super.key, required this.counter, required this.contextMenuBuilder});

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text('$counter'),
        // This does not work
        SelectableText('selectable text 1', contextMenuBuilder: (context, editableTextState) {
          print('contextMenuBuilder 1 is called');
          return AdaptiveTextSelectionToolbar.buttonItems(
            buttonItems: [
              ContextMenuButtonItem(onPressed: () {}, label: 'menu'),
              ...editableTextState.contextMenuButtonItems,
            ],
            anchors: editableTextState.contextMenuAnchors,
          );
        }),
        // This does work
        SelectableText('selectable text 2', contextMenuBuilder: contextMenuBuilder),
      ],
    );
  }
}
